mapper.select:
SELECT ef.SEQ, ef.CODE_NO, ef.CODE_NAME, ef.FORMULA, ef.REMARK, ef.ACTIVITY, TO_CHAR(ef.ORDERNO) AS ORDER_NO, TO_CHAR(ef.CREATE_DATE, 'YYYY-MM-DD HH24:MI:SS') AS CREATE_DATE, GET_UPDATED_INFO(ef.CREATED_BY) || ' ' || ef.CREATED_IP AS CREATED_BY, TO_CHAR(ef.UPDATE_DATE, 'YYYY-MM-DD HH24:MI') AS UPDATE_DATE, GET_UPDATED_INFO(ef.UPDATED_BY) || ' ' || ef.UPDATED_IP AS UPDATED_BY FROM EVS_FORMULA ef WHERE ef.CPNY_ID = #{cpnyId, jdbcType=VARCHAR}
AND ef.CODE_NO LIKE '%' || #{codeNoSearch, jdbcType=VARCHAR} || '%'
AND ef.CODE_NAME LIKE '%' || #{codeNameSearch, jdbcType=VARCHAR} || '%'
AND ef.ACTIVITY = #{activitySearch, jdbcType=VARCHAR}
ORDER BY TO_NUMBER(ef.ORDERNO) NULLS LAST, TO_NUMBER(ef.SEQ)

mapper.delete:
UPDATE EVS_FORMULA
SET UPDATE_DATE = SYSDATE,
    UPDATED_BY = #{adminID, jdbcType=VARCHAR},
    ACTIVITY = 0,
    UPDATED_IP = #{adminIP, jdbcType=VARCHAR}
WHERE SEQ     = #{seq,    jdbcType=VARCHAR}
  AND CPNY_ID = #{cpnyId, jdbcType=VARCHAR}
